    <script type="text/javascript" >  
    


    $("#firstloginpage-firstlogin-firstlogin-num-prefisso").click(function(){
            if($(".dropdownnum").hasClass('openlist')){
                $('.dropdownnum').removeClass('openlist');
            }else{
                $('.dropdownnum').addClass('openlist');
            }
    });
    $(".dropdownnum li").click(function(){
        var text = $(this).text().replace(/[^0-9]/gi,'');
        text = parseInt(text,10);
        $("#firstloginpage-firstlogin-firstlogin-num-prefisso .isp-dropdown-buttonLabel").text("+"+text);
        $('.dropdownnum').removeClass('openlist');
        $("#CodePhoneSelected2").val("+"+text);
    });

    $( "#firstloginpage-firstlogincontroller-firstlogin-num" ).focus(function() {
        $(".loginfirsterrors").removeClass('ng-hide');
    });
    $( "#firstloginpage-firstlogincontroller-firstlogin-num" ).focusout(function() {
        $(".loginfirsterrors").addClass('ng-hide');
    });
    </script>
